BEGIN TRANSACTION;
CREATE TABLE answer_logs (
        id           INTEGER PRIMARY KEY AUTOINCREMENT,
        play_log_id  INTEGER REFERENCES play_logs(id),
        question_id  INTEGER,
        player_name  TEXT,
        answer       TEXT,
        is_correct   INTEGER,
        buzz_time_ms INTEGER,
        buzz_order   INTEGER,
        points       INTEGER,
        answered_at  TEXT
    );
CREATE TABLE invalid_reports (
        id          INTEGER PRIMARY KEY AUTOINCREMENT,
        question_id INTEGER,
        play_log_id INTEGER REFERENCES play_logs(id),
        player_name TEXT,
        reported_at TEXT    DEFAULT (datetime('now'))
    );
COMMIT;
